import React, { useState } from 'react';
import DragDropCanvas from './components/DragDropCanvas';
import VisualizationLibrary from './components/VisualizationLibrary';
import ExportManager from './components/ExportManager';
import DataConnections from './components/DataConnections';
import VariablesView from './components/VariablesView';
import CodeEditor from './components/CodeEditor';
import BuilderPageTabs from './components/BuilderPageTabs';
import { WindowPanel, BackgroundConfig, DataConnection, CodeEditorConfig, BuilderPage } from './types';
import './App.css';

const App: React.FC = () => {
  // Builder pages state (only for the builder tab)
  const [builderPages, setBuilderPages] = useState<BuilderPage[]>([
    {
      id: 'page-1',
      name: 'Page 1',
      windows: [],
      backgroundConfig: {
        width: 1200,
        height: 800,
        color: '#ffffff'
      }
    }
  ]);
  const [activeBuilderPageId, setActiveBuilderPageId] = useState<string>('page-1');

  // Global state (shared across all pages)
  const [dataConnections, setDataConnections] = useState<DataConnection>({
    apiConnections: [],
    globalVariables: {}
  });
  const [activeTab, setActiveTab] = useState<'builder' | 'data' | 'variables' | 'editor'>('builder');
  const [leftPanelVisible, setLeftPanelVisible] = useState<boolean>(true);
  const [rightPanelVisible, setRightPanelVisible] = useState<boolean>(true);
  const [codeEditorConfigs, setCodeEditorConfigs] = useState<CodeEditorConfig[]>([
    {
      id: 'default-config',
      name: 'Default Editor',
      elements: [],
      htmlCode: '',
      jsCode: '',
      cssCode: ''
    }
  ]);

  // Helper functions to get current page data
  const getCurrentBuilderPage = (): BuilderPage => {
    return builderPages.find(p => p.id === activeBuilderPageId) || builderPages[0];
  };

  // Computed values for current page
  const windows = getCurrentBuilderPage().windows;
  const backgroundConfig = getCurrentBuilderPage().backgroundConfig;

  const handleAddTemplate = (type: 'javascript' | 'html', template: any) => {
    const newWindow: WindowPanel = {
      id: `window-${Date.now()}`,
      title: template.name,
      type,
      content: type === 'html' ? template.code : '',
      position: { 
        x: Math.random() * 300 + 50, 
        y: Math.random() * 200 + 50 
      },
      size: { width: 400, height: 300 },
      jsCode: type === 'javascript' ? template.code : undefined
    };

    setWindows(prev => [...prev, newWindow]);
  };

  const handleWindowsChange = (newWindows: WindowPanel[]) => {
    setWindows(newWindows);
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      flexDirection: 'column',
      fontFamily: '"Segoe UI", "Arial", sans-serif',
      backgroundColor: '#f7f8fa',
      color: '#2c3e50'
    }}>
      {/* Header */}
      <header style={{
        padding: '15px 20px',
        backgroundColor: '#1a1a1a',
        color: 'white',
        borderBottom: '3px solid #0066cc',
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img 
            src="/evs-logo.png" 
            alt="EVS Automation" 
            style={{ 
              height: '65px', 
              width: 'auto'
            }} 
          />
          <div>
            <h1 style={{ 
              margin: 0, 
              fontSize: '28px',
              fontWeight: '700',
              letterSpacing: '0.5px',
              fontFamily: '"Segoe UI", "Arial Black", sans-serif'
            }}>
              Web App & HMI Builder
            </h1>
            <p style={{ 
              margin: '2px 0 0 0', 
              fontSize: '13px', 
              opacity: 0.85,
              fontWeight: '500',
              letterSpacing: '0.3px',
              textTransform: 'uppercase'
            }}>
              Industrial Web Applications & Data Visualization
            </p>
          </div>
        </div>
      </header>

      {/* Tab Navigation */}
      <div style={{
