            <button
              onClick={() => setActiveTab('variables')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'variables' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'variables' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'variables' ? '700' : '600',
                color: activeTab === 'variables' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
