                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'inset 1px 0 0 rgba(0,102,204,0.1)';
                }}
              >
                {/* Clickable Tab Header */}
                <div 
                  onClick={() => setRightPanelVisible(false)}
                  style={{
                    padding: '12px 16px',
                    backgroundColor: '#0066cc',
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    borderBottom: '1px solid #d6dbdf',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none'
